<script setup lang="ts">
import {computed,onBeforeUnmount,onMounted,ref} from 'vue';import {useRoute} from 'vue-router';import {Check,Clock,CopyDocument,Lock,Phone,Refresh,Warning} from '@element-plus/icons-vue';import {ElMessage} from 'element-plus';import {getDeposit,type DepositIntent,type DepositStatus} from '../api/checkout';import {clock,formatEtb,secondsRemaining} from '../lib/format';
import {useCheckoutSessionStore} from '../stores/session';
const route=useRoute();const session=useCheckoutSessionStore();const intent=ref<DepositIntent>();const loading=ref(true);const error=ref('');const now=ref(Date.now());let ticker:number|undefined;let polling:number|undefined;const remaining=computed(()=>intent.value?secondsRemaining(intent.value.expiresAt,now.value):0);const lateRemaining=computed(()=>intent.value?secondsRemaining(intent.value.lateGraceEndsAt,now.value):0);const status=computed<DepositStatus>(()=>{if(!intent.value)return'awaiting_payment';if(intent.value.status==='success'||intent.value.status==='failed'||intent.value.status==='manual_review')return intent.value.status;if(remaining.value===0&&lateRemaining.value>0)return'late_grace';if(lateRemaining.value===0)return'expired';return intent.value.status});
const progress=computed(()=>Math.max(0,Math.min(100,remaining.value/Math.max(1,intent.value?.countdownSeconds??600)*100)));const statusCopy=computed(()=>({awaiting_payment:['Waiting for your payment','Send the exact amount from your Telebirr account.'],late_grace:['Payment window ended','If you already paid, we are still checking for your transfer.'],matching:['Confirming your payment','We received a possible match and are checking it now.'],manual_review:['We are reviewing your payment','Support has the evidence. You do not need to pay again.'],success:['Payment confirmed','Your merchant account has been credited.'],expired:['Payment request expired','Create a new payment request with the merchant.'],failed:['We could not complete this payment','Please return to the merchant and try again.']}[status.value]));
async function load(){try{intent.value=await getDeposit(String(route.params.txRef),String(route.query.token||''));now.value=Date.now();const scenario=String(route.query.scenario||'');if(['success','manual_review','failed'].includes(scenario))intent.value.status=scenario as DepositStatus}catch(e){error.value=e instanceof Error?e.message:'Unable to load payment'}finally{loading.value=false}}
function copy(value:string){navigator.clipboard?.writeText(value);ElMessage.success('Copied')}
async function sent(){if(!intent.value||status.value!=='awaiting_payment')return;intent.value.status='matching';if(import.meta.env.VITE_USE_MOCKS==='true'||route.params.txRef==='demo'){setTimeout(()=>{if(intent.value&&route.query.scenario!=='stay')intent.value.status='success'},2600);return}await load()}
function returnToMerchant(){if(intent.value?.returnUrl)window.location.assign(intent.value.returnUrl)}
onMounted(()=>{session.begin('deposit',String(route.params.txRef));load();ticker=window.setInterval(()=>now.value=Date.now(),1000);polling=window.setInterval(()=>{if(intent.value&&!['success','failed','expired'].includes(status.value)&&import.meta.env.VITE_USE_MOCKS!=='true')load()},5000)});onBeforeUnmount(()=>{clearInterval(ticker);clearInterval(polling)})
</script>
<template><div class="checkout-page"><header class="checkout-header"><div class="brand"><div class="brand-mark">O</div><div><strong>OrbitPay</strong><small>Secure payment</small></div></div><div class="secure"><Lock/><span>Encrypted checkout</span></div></header><main class="checkout-main"><div v-if="loading" class="loading"><el-skeleton :rows="7" animated/></div><div v-else-if="error" class="error-card"><el-icon><Warning/></el-icon><h2>Payment unavailable</h2><p>{{error}}</p><el-button :icon="Refresh" @click="load">Try again</el-button></div><div v-else-if="intent" class="checkout-card">
<aside class="order-pane"><span>Payment to</span><h1>{{intent.merchantName}}</h1><p>Telebirr deposit</p><div class="order-amount"><span>Amount due</span><strong>ETB {{formatEtb(intent.amount)}}</strong></div><div class="order-meta"><div><span>Reference</span><b>{{intent.reference}}</b></div><div><span>Currency</span><b>ETB</b></div></div></aside>
<section class="action-pane"><template v-if="status==='awaiting_payment'||status==='late_grace'"><div class="step-head"><span class="status-pill"><i/> {{status==='late_grace'?'Checking late payment':'Awaiting payment'}}</span><h2>Send with Telebirr</h2><p>Open Telebirr or dial <b>*127#</b>, then send the exact amount to:</p></div><div class="receiver"><div class="phone-icon"><Phone/></div><div><span>Receiver number</span><strong>{{intent.receiverPhone}}</strong><small>Registered to {{intent.receiverName}}</small></div><el-button circle :icon="CopyDocument" @click="copy(intent.receiverPhone)"/></div><div class="exact"><span>Send exactly</span><strong>ETB {{formatEtb(intent.amount)}}</strong><el-button link :icon="CopyDocument" @click="copy(intent.amount)">Copy</el-button></div><div :class="['timer',{'late':status==='late_grace'}]"><div><el-icon><Clock/></el-icon><span>{{status==='late_grace'?'Late-check window':'Time remaining'}}</span></div><strong>{{clock(status==='late_grace'?lateRemaining:remaining)}}</strong><el-progress :percentage="status==='late_grace'?Math.round(lateRemaining/Math.max(1,intent.lateGraceSeconds)*100):progress" :show-text="false" :stroke-width="5" :color="status==='late_grace'?'#d18a24':'#5558d9'"/></div><el-button v-if="status==='awaiting_payment'" type="primary" size="large" class="sent-button" @click="sent">I’ve sent the money</el-button><p class="note">You do not need to enter a confirmation code. Keep your Telebirr SMS until this payment is complete.</p></template>
<template v-else><div :class="['outcome',status]"><div class="outcome-icon"><el-icon v-if="status==='success'"><Check/></el-icon><el-icon v-else-if="status==='matching'"><Refresh class="spin"/></el-icon><el-icon v-else><Warning/></el-icon></div><span class="status-pill"><i/> {{status.replace('_',' ')}}</span><h2>{{statusCopy[0]}}</h2><p>{{statusCopy[1]}}</p><div v-if="status==='success'" class="receipt"><div><span>Credited amount</span><strong>ETB {{formatEtb(intent.creditedAmount??intent.amount)}}</strong></div><div><span>Reference</span><strong>{{intent.reference}}</strong></div></div><el-button v-if="status==='success'" type="primary" size="large" class="sent-button" @click="returnToMerchant">Return to {{intent.merchantName}}</el-button><el-button v-else-if="status==='expired'||status==='failed'" size="large" class="sent-button" @click="returnToMerchant">Return to merchant</el-button></div></template></section></div></main><footer class="checkout-footer">Payments are processed over Telebirr · OrbitPay never asks for your Telebirr PIN</footer></div></template>
<style scoped>
.loading,.error-card{width:min(92vw,560px);padding:30px;background:#fff;border:1px solid var(--line);border-radius:17px}.error-card{text-align:center}.error-card>.el-icon{font-size:35px;color:var(--danger)}.error-card p{font-size:11px;color:var(--muted)}.step-head h2{font:800 24px 'Manrope';margin:16px 0 6px;letter-spacing:-.04em}.step-head p{font-size:11px;color:var(--muted);line-height:1.55;margin:0}.receiver{display:grid;grid-template-columns:42px 1fr auto;gap:11px;align-items:center;border:1px solid var(--line);border-radius:12px;padding:14px;margin:22px 0 10px}.phone-icon{width:40px;height:40px;border-radius:10px;background:#eeeeff;color:var(--primary);display:grid;place-items:center}.phone-icon svg{width:20px}.receiver span,.receiver strong,.receiver small{display:block}.receiver span{font-size:9px;color:var(--muted);text-transform:uppercase}.receiver strong{font:800 19px 'Manrope';letter-spacing:.02em;margin:3px 0}.receiver small{font-size:9px;color:var(--teal)}.exact{display:flex;align-items:center;gap:8px;padding:12px 14px;background:#f5f6fa;border-radius:10px}.exact span{font-size:10px;color:var(--muted)}.exact strong{font:700 14px 'Manrope';margin-left:auto}.timer{padding:13px 14px;margin-top:16px;border:1px solid #e4e4fb;background:#f8f8ff;border-radius:11px}.timer>div{display:flex;align-items:center;gap:6px;font-size:9px;color:var(--muted)}.timer>strong{display:block;text-align:right;font:800 20px 'Manrope';color:var(--primary);margin-top:-17px}.timer .el-progress{margin-top:11px}.timer.late{background:#fff9ee;border-color:#f3dfbd}.timer.late>strong{color:#bb7111}.sent-button{width:100%;margin-top:16px;min-height:46px;font-weight:700}.note{text-align:center;font-size:9px!important;color:var(--muted);line-height:1.45;margin:12px 10px 0}.outcome{text-align:center;padding-top:15px}.outcome-icon{width:72px;height:72px;border-radius:50%;display:grid;place-items:center;margin:0 auto 17px;background:#eeeeff;color:var(--primary);font-size:32px}.outcome.success .outcome-icon{background:#e6f7f2;color:var(--teal)}.outcome.failed .outcome-icon,.outcome.expired .outcome-icon{background:#ffeaee;color:var(--danger)}.outcome h2{font:800 24px 'Manrope';margin:15px 0 7px;letter-spacing:-.04em}.outcome>p{font-size:11px;color:var(--muted);line-height:1.55}.receipt{background:#f6f7fa;border-radius:11px;padding:8px 14px;margin:22px 0;text-align:left}.receipt div{display:flex;justify-content:space-between;padding:10px 0;border-bottom:1px solid var(--line)}.receipt div:last-child{border:0}.receipt span{font-size:10px;color:var(--muted)}.receipt strong{font-size:11px}.spin{animation:spin 1.4s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}
</style>
